// ============================================================================
// SDK Helper Functions and Macros
// ============================================================================

namespace sdk {

    // Helper to determine the const-qualified return type
    // For non-pointer types: const T&
    // For pointer types: T* const& (const pointer, not pointer-to-const)
    template <typename T>
    struct const_field_type {
        using type = const T&;
    };

    template <typename T>
    struct const_field_type<T*> {
        using type = T* const&;
    };

    // Convert `this + offset` to a typed reference. Zero-overhead in
    // release builds; produces an lvalue you can read or assign to.
    template <typename T>
    inline T& field_ref(void* base, std::ptrdiff_t off) noexcept {
        return *reinterpret_cast<T*>(reinterpret_cast<std::byte*>(base) + off);
    }

    template <typename T>
    inline typename const_field_type<T>::type field_ref(const void* base, std::ptrdiff_t off) noexcept {
        return *reinterpret_cast<T*>(const_cast<std::byte*>(reinterpret_cast<const std::byte*>(base)) + off);
    }

} // namespace sdk

// SCHEMA_FIELD(type, name, offset)
//
// Expands to a pair of inline accessors:
//
//     T&       name()       { return sdk::field_ref<T>(this, off); }
//     const T& name() const { return sdk::field_ref<T>(this, off); }
//
// For pointer types, the const version returns T* const& (const pointer, not pointer to const)
// Use it as: `pawn->m_iHealth() = 100;`
#define SCHEMA_FIELD(TYPE, NAME, OFFSET)                                           \
    inline TYPE&       NAME()       noexcept { return ::sdk::field_ref<TYPE>(this, (OFFSET)); } \
    inline auto        NAME() const noexcept -> decltype(::sdk::field_ref<TYPE>(this, (OFFSET))) { return ::sdk::field_ref<TYPE>(this, (OFFSET)); }

// SCHEMA_PAD(name, size) — anonymous padding when you want to
// pre-declare a struct layout exactly. Optional.
#define SCHEMA_PAD(NAME, SIZE) std::byte NAME[(SIZE)]

